import React, { useState, useEffect } from "react";
import axios from "axios";

function FirmPanel() {
  const [firms, setFirms] = useState([]);
  const [newFirm, setNewFirm] = useState("");
  const [selectedFirm, setSelectedFirm] = useState(null);
  const [docs, setDocs] = useState([]);

  useEffect(() => {
    axios.get("/firms").then(res => setFirms(res.data));
  }, []);

  const addFirm = async () => {
    if (!newFirm.trim()) return;
    const res = await axios.post("/firms", { name: newFirm });
    setFirms([...firms, res.data]);
    setNewFirm("");
  };

  const selectFirm = async (id) => {
    setSelectedFirm(id);
    const res = await axios.get(`/firms/${id}/docs`);
    setDocs(res.data);
  };

  const uploadDoc = async (e, type) => {
    if (!selectedFirm) return;
    const formData = new FormData();
    formData.append("file", e.target.files[0]);
    formData.append("type", type);
    await axios.post(`/firms/${selectedFirm}/docs`, formData);
    const res = await axios.get(`/firms/${selectedFirm}/docs`);
    setDocs(res.data);
  };

  const openDoc = async (id) => {
    await axios.get(`/open/${id}`);
  };

  return (
    <div>
      <h2>Firmalar</h2>
      <input
        value={newFirm}
        onChange={e => setNewFirm(e.target.value)}
        placeholder="Firma adı"
      />
      <button onClick={addFirm}>Firma Ekle</button>

      <ul>
        {firms.map((f, index) => (
          <li key={f.id}>
            <button onClick={() => selectFirm(f.id)}>
              {index + 1}. {f.name}
            </button>
          </li>
        ))}
      </ul>

      {selectedFirm && (
        <div>
          <h3>Belgeler</h3>
          <label>
            Belge Yükle:
            <input type="file" onChange={(e) => uploadDoc(e, "Genel Belge")} />
          </label>

          <table border="1" style={{ marginTop: "20px", width: "100%" }}>
            <thead>
              <tr>
                <th>S.N.</th>
                <th>Firma Unvanı</th>
                <th>Belge Türü</th>
                <th>Doküman</th>
              </tr>
            </thead>
            <tbody>
              {docs.map((d, i) => (
                <tr key={d.id}>
                  <td>{i + 1}</td>
                  <td>{firms.find(f => f.id === d.firmId)?.name}</td>
                  <td>{d.type}</td>
                  <td>
                    {d.filename}{" "}
                    <button onClick={() => openDoc(d.id)}>Aç</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default FirmPanel;
